func main() {
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		// The network monkey is here to grab and print the request content!
		fmt.Println("A monkey has arrived at the server!")
		fmt.Println("Request Method:", r.Method)
		fmt.Println("Request URL:", r.URL)
		fmt.Println("Request Headers:")
		r.Header.ForEach(func(k, v []byte) {
			fmt.Println(" -", string(k), ":", string(v))
		})
		fmt.Println("Request Body:")
		body, err := readRequestBody(r)
		if err != nil {
			fmt.Println("Error reading request body:", err)
			return
		}
		fmt.Println(string(body))
	})

	// Start the server on port 8080 and wait for requests
	http.ListenAndServe(":8080", nil)
}

func readRequestBody(r *http.Request) ([]byte, error) {
	if r.Body == nil {
		return nil, fmt.Errorf("request body is nil")
	}

	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		return nil, err
	}

	// Close the body to avoid leaking resources
	err = r.Body.Close()
	if err != nil {
		return nil, err
	}

	return body, nil
}
```

